module noise_suppression(
    input clk,
    input rst,
    input signal_in,
    output reg signal_out
);
    reg [2:0] ns_state; // 3-bit ns_state to store the last three inputs

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            ns_state <= 3'b000;
            signal_out <= 0;
        end else begin
            ns_state <= {ns_state[1:0], signal_in}; // Shift in the new signal
            // Output 1 only if the last three signals are all 1
            if (ns_state == 3'b111) begin
                signal_out <= 1;
            end else begin
                signal_out <= 0;
            end
        end
    end
endmodule
